const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const API_KEY = process.env.API_KEY || 'change-me';
const MAX_SCORE_PER_LEVEL = 1000000;
const MIN_TIME_MS = 1000;
const MAX_TIME_MS = 24 * 60 * 60 * 1000;

const userState = new Map();

function getUser(userId) {
  if (!userState.has(userId)) {
    userState.set(userId, {
      completedLevels: new Map(),
      claimedRewards: new Set()
    });
  }
  return userState.get(userId);
}

function computeReward(level, score, timeMs) {
  let coins = 0;
  let gems = 0;

  if (score >= 1000) coins += 50;
  if (score >= 5000) coins += 100;
  if (score >= 10000) coins += 250;

  if (timeMs <= 60000) gems += 1;
  if (timeMs <= 30000) gems += 2;
  if (timeMs <= 15000) gems += 3;

  if (level % 5 === 0) coins += 100;
  if (level % 10 === 0) gems += 5;

  return { coins, gems };
}

function clampInt(value, min, max) {
  const n = Number(value);
  if (!Number.isFinite(n)) return null;
  const i = Math.floor(n);
  return Math.max(min, Math.min(max, i));
}

function auth(req, res, next) {
  const apiKey = req.header('x-api-key');
  if (apiKey !== API_KEY) {
    return res.status(401).json({ error: 'unauthorized' });
  }
  next();
}

app.use(auth);

app.post('/api/levels/complete', (req, res) => {
  const { userId, level, score, timeMs } = req.body || {};

  if (!userId || typeof userId !== 'string') {
    return res.status(400).json({ error: 'invalid_userId' });
  }

  const levelNum = clampInt(level, 1, 1000000);
  const scoreNum = clampInt(score, 0, MAX_SCORE_PER_LEVEL);
  const timeNum = clampInt(timeMs, MIN_TIME_MS, MAX_TIME_MS);

  if (levelNum === null || scoreNum === null || timeNum === null) {
    return res.status(400).json({ error: 'invalid_payload' });
  }

  const user = getUser(userId);
  const existing = user.completedLevels.get(levelNum) || { bestScore: 0, bestTimeMs: MAX_TIME_MS, completedAt: null };

  const improved = scoreNum > existing.bestScore || (scoreNum === existing.bestScore && timeNum < existing.bestTimeMs);

  if (improved) {
    user.completedLevels.set(levelNum, {
      bestScore: Math.max(existing.bestScore, scoreNum),
      bestTimeMs: Math.min(existing.bestTimeMs, timeNum),
      completedAt: new Date().toISOString()
    });
  }

  const reward = computeReward(levelNum, scoreNum, timeNum);
  const completionId = crypto.randomUUID();

  return res.json({
    ok: true,
    completionId,
    level: levelNum,
    score: scoreNum,
    timeMs: timeNum,
    reward
  });
});

app.post('/api/rewards/claim', (req, res) => {
  const { userId, level, completionId } = req.body || {};

  if (!userId || typeof userId !== 'string') {
    return res.status(400).json({ error: 'invalid_userId' });
  }

  const levelNum = clampInt(level, 1, 1000000);
  if (levelNum === null || typeof completionId !== 'string' || !completionId) {
    return res.status(400).json({ error: 'invalid_payload' });
  }

  const user = getUser(userId);
  if (user.claimedRewards.has(`${levelNum}:${completionId}`)) {
    return res.status(409).json({ error: 'already_claimed' });
  }

  const completion = user.completedLevels.get(levelNum);
  if (!completion) {
    return res.status(404).json({ error: 'level_not_completed' });
  }

  const reward = computeReward(levelNum, completion.bestScore, completion.bestTimeMs);

  user.claimedRewards.add(`${levelNum}:${completionId}`);

  return res.json({
    ok: true,
    level: levelNum,
    reward,
    claimedAt: new Date().toISOString()
  });
});

app.get('/api/users/:userId/state', (req, res) => {
  const { userId } = req.params;
  const user = getUser(userId);
  const levels = [];
  for (const [level, data] of user.completedLevels.entries()) {
    levels.push({ level, ...data });
  }
  res.json({
    ok: true,
    userId,
    completedLevels: levels
  });
});

app.use((err, req, res, next) => {
  res.status(500).json({ error: 'internal_error' });
});

app.listen(PORT, () => {
  console.log(`API listening on port ${PORT}`);
});